grid = {
    "substation-1": ["substation-2", "substation-3"],
    "substation-2": ["substation-1", "substation-4"],
    "substation-3": ["substation-1"],
    "substation-4": ["substation-2"],
}

def bfs(grid, start):
    visited, queue = {start}, [start]
    order = []
    while queue:
        node = queue.pop(0)
        order.append(node)
        for neighbor in grid[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)
    return order

print(bfs(grid, "substation-1"))
